const files = {"/":{"type":"text/html; charset=utf-8","body":"<!doctype html>\n<html lang=\"zh-CN\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>同频影院</title>\n  <link rel=\"stylesheet\" href=\"./styles.css\">\n</head>\n<body>\n  <main class=\"app-shell\">\n    <header class=\"topbar\">\n      <div>\n        <p class=\"eyebrow\">同步观影房间</p>\n        <h1>同频影院</h1>\n      </div>\n      <div class=\"room-chip\" title=\"当前房间号\">\n        <span>房间</span>\n        <strong id=\"roomCode\">TP-0726</strong>\n      </div>\n    </header>\n\n    <section class=\"layout\">\n      <section class=\"watch-stage\" aria-label=\"观影区\">\n        <div class=\"screen\">\n          <img src=\"./assets/theater-poster.svg\" alt=\"同频影院观影画面\" class=\"poster\">\n          <div class=\"screen-overlay\">\n            <div>\n              <p class=\"eyebrow\">正在播放</p>\n              <h2 id=\"movieTitle\">今晚的片单</h2>\n            </div>\n            <button class=\"icon-button\" id=\"favoriteBtn\" title=\"标记本片\">☆</button>\n          </div>\n        </div>\n\n        <div class=\"progress-block\">\n          <div class=\"time-row\">\n            <span id=\"currentTime\">00:12:48</span>\n            <span id=\"duration\">01:48:00</span>\n          </div>\n          <input id=\"progressRange\" class=\"range\" type=\"range\" min=\"0\" max=\"6480\" value=\"768\" aria-label=\"播放进度\">\n        </div>\n\n        <div class=\"controls\" aria-label=\"播放控制\">\n          <button class=\"control-button\" id=\"backBtn\" title=\"后退15秒\">↺ 15s</button>\n          <button class=\"primary-button\" id=\"playBtn\" title=\"播放或暂停\">▶ 播放</button>\n          <button class=\"control-button\" id=\"forwardBtn\" title=\"前进15秒\">15s ↻</button>\n          <button class=\"control-button\" id=\"syncBtn\" title=\"让所有人同步到房主时间\">同步</button>\n        </div>\n      </section>\n\n      <aside class=\"side-panel\" aria-label=\"房间状态\">\n        <section class=\"panel\">\n          <div class=\"panel-head\">\n            <h2>同步状态</h2>\n            <span id=\"syncBadge\" class=\"status good\">同频</span>\n          </div>\n          <div class=\"stat-grid\">\n            <div>\n              <span>房主时间</span>\n              <strong id=\"hostTime\">00:12:48</strong>\n            </div>\n            <div>\n              <span>本机延迟</span>\n              <strong id=\"latency\">+0.18s</strong>\n            </div>\n            <div>\n              <span>在线成员</span>\n              <strong id=\"memberCount\">4</strong>\n            </div>\n            <div>\n              <span>房主模式</span>\n              <strong id=\"hostMode\">开启</strong>\n            </div>\n          </div>\n        </section>\n\n        <section class=\"panel\">\n          <div class=\"panel-head\">\n            <h2>成员</h2>\n            <button class=\"small-button\" id=\"copyInviteBtn\" title=\"复制邀请文案\">复制邀请</button>\n          </div>\n          <form class=\"inline-form compact-form\" id=\"identityForm\">\n            <input id=\"viewerName\" type=\"text\" placeholder=\"你的昵称\" autocomplete=\"off\">\n            <button type=\"submit\" class=\"small-button\">保存</button>\n          </form>\n          <ul class=\"member-list\" id=\"memberList\"></ul>\n        </section>\n      </aside>\n    </section>\n\n    <section class=\"workspace\">\n      <section class=\"panel p2p-panel\">\n        <div class=\"panel-head\">\n          <h2>直连配对</h2>\n          <span class=\"muted\" id=\"p2pStatus\">未连接</span>\n        </div>\n        <div class=\"pair-grid\">\n          <button class=\"primary-button\" id=\"createOfferBtn\" type=\"button\">我是房主</button>\n          <button class=\"small-button\" id=\"createAnswerBtn\" type=\"button\">我是观众</button>\n        </div>\n        <label class=\"field-label\" for=\"signalBox\">配对码</label>\n        <textarea id=\"signalBox\" class=\"signal-box\" placeholder=\"房主：点“我是房主”后复制这里发给对象。观众：粘贴房主给你的配对码后点“我是观众”。\"></textarea>\n        <div class=\"pair-grid\">\n          <button class=\"small-button\" id=\"applySignalBtn\" type=\"button\">应用对方回应码</button>\n          <button class=\"small-button\" id=\"copySignalBtn\" type=\"button\">复制配对码</button>\n        </div>\n        <div class=\"notice\">\n          GitHub Pages 可稳定托管页面；配对成功后，播放/暂停、拖动进度、片单和聊天通过你们两台设备点对点互通，不经过服务器。\n        </div>\n      </section>\n\n      <section class=\"panel share-panel\">\n        <div class=\"panel-head\">\n          <h2>异地入口</h2>\n          <span class=\"muted\">发给对象</span>\n        </div>\n        <div class=\"share-box\">\n          <label for=\"shareUrl\">房间链接</label>\n          <input id=\"shareUrl\" type=\"text\" readonly>\n          <button class=\"primary-button\" id=\"copyUrlBtn\" type=\"button\">复制链接</button>\n        </div>\n        <div class=\"notice\">\n          打开同一个房间链接后，播放/暂停、拖动进度、片单和聊天会自动互通。若网络波动，页面会自动重试同步。\n        </div>\n      </section>\n\n      <section class=\"panel queue-panel\">\n        <div class=\"panel-head\">\n          <h2>影片队列</h2>\n          <button class=\"small-button\" id=\"clearQueueBtn\" title=\"清空新增队列\">清空</button>\n        </div>\n        <form class=\"inline-form\" id=\"queueForm\">\n          <input id=\"queueTitle\" type=\"text\" placeholder=\"片名或视频链接\" autocomplete=\"off\">\n          <button type=\"submit\" class=\"primary-button\">加入</button>\n        </form>\n        <ul class=\"queue-list\" id=\"queueList\"></ul>\n      </section>\n\n      <section class=\"panel chat-panel\">\n        <div class=\"panel-head\">\n          <h2>同频聊天</h2>\n          <span class=\"muted\">在线互通</span>\n        </div>\n        <div class=\"chat-log\" id=\"chatLog\"></div>\n        <form class=\"inline-form\" id=\"chatForm\">\n          <input id=\"chatInput\" type=\"text\" placeholder=\"发一句观影弹幕\" autocomplete=\"off\">\n          <button type=\"submit\" class=\"primary-button\">发送</button>\n        </form>\n      </section>\n\n      <section class=\"panel timeline-panel\">\n        <div class=\"panel-head\">\n          <h2>房间时间线</h2>\n          <span class=\"muted\" id=\"saveState\">已保存</span>\n        </div>\n        <ol class=\"timeline\" id=\"timelineList\"></ol>\n      </section>\n    </section>\n  </main>\n\n  <script src=\"./app.js\"></script>\n</body>\n</html>\n"},"/index.html":{"type":"text/html; charset=utf-8","body":"<!doctype html>\n<html lang=\"zh-CN\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>同频影院</title>\n  <link rel=\"stylesheet\" href=\"./styles.css\">\n</head>\n<body>\n  <main class=\"app-shell\">\n    <header class=\"topbar\">\n      <div>\n        <p class=\"eyebrow\">同步观影房间</p>\n        <h1>同频影院</h1>\n      </div>\n      <div class=\"room-chip\" title=\"当前房间号\">\n        <span>房间</span>\n        <strong id=\"roomCode\">TP-0726</strong>\n      </div>\n    </header>\n\n    <section class=\"layout\">\n      <section class=\"watch-stage\" aria-label=\"观影区\">\n        <div class=\"screen\">\n          <img src=\"./assets/theater-poster.svg\" alt=\"同频影院观影画面\" class=\"poster\">\n          <div class=\"screen-overlay\">\n            <div>\n              <p class=\"eyebrow\">正在播放</p>\n              <h2 id=\"movieTitle\">今晚的片单</h2>\n            </div>\n            <button class=\"icon-button\" id=\"favoriteBtn\" title=\"标记本片\">☆</button>\n          </div>\n        </div>\n\n        <div class=\"progress-block\">\n          <div class=\"time-row\">\n            <span id=\"currentTime\">00:12:48</span>\n            <span id=\"duration\">01:48:00</span>\n          </div>\n          <input id=\"progressRange\" class=\"range\" type=\"range\" min=\"0\" max=\"6480\" value=\"768\" aria-label=\"播放进度\">\n        </div>\n\n        <div class=\"controls\" aria-label=\"播放控制\">\n          <button class=\"control-button\" id=\"backBtn\" title=\"后退15秒\">↺ 15s</button>\n          <button class=\"primary-button\" id=\"playBtn\" title=\"播放或暂停\">▶ 播放</button>\n          <button class=\"control-button\" id=\"forwardBtn\" title=\"前进15秒\">15s ↻</button>\n          <button class=\"control-button\" id=\"syncBtn\" title=\"让所有人同步到房主时间\">同步</button>\n        </div>\n      </section>\n\n      <aside class=\"side-panel\" aria-label=\"房间状态\">\n        <section class=\"panel\">\n          <div class=\"panel-head\">\n            <h2>同步状态</h2>\n            <span id=\"syncBadge\" class=\"status good\">同频</span>\n          </div>\n          <div class=\"stat-grid\">\n            <div>\n              <span>房主时间</span>\n              <strong id=\"hostTime\">00:12:48</strong>\n            </div>\n            <div>\n              <span>本机延迟</span>\n              <strong id=\"latency\">+0.18s</strong>\n            </div>\n            <div>\n              <span>在线成员</span>\n              <strong id=\"memberCount\">4</strong>\n            </div>\n            <div>\n              <span>房主模式</span>\n              <strong id=\"hostMode\">开启</strong>\n            </div>\n          </div>\n        </section>\n\n        <section class=\"panel\">\n          <div class=\"panel-head\">\n            <h2>成员</h2>\n            <button class=\"small-button\" id=\"copyInviteBtn\" title=\"复制邀请文案\">复制邀请</button>\n          </div>\n          <form class=\"inline-form compact-form\" id=\"identityForm\">\n            <input id=\"viewerName\" type=\"text\" placeholder=\"你的昵称\" autocomplete=\"off\">\n            <button type=\"submit\" class=\"small-button\">保存</button>\n          </form>\n          <ul class=\"member-list\" id=\"memberList\"></ul>\n        </section>\n      </aside>\n    </section>\n\n    <section class=\"workspace\">\n      <section class=\"panel p2p-panel\">\n        <div class=\"panel-head\">\n          <h2>直连配对</h2>\n          <span class=\"muted\" id=\"p2pStatus\">未连接</span>\n        </div>\n        <div class=\"pair-grid\">\n          <button class=\"primary-button\" id=\"createOfferBtn\" type=\"button\">我是房主</button>\n          <button class=\"small-button\" id=\"createAnswerBtn\" type=\"button\">我是观众</button>\n        </div>\n        <label class=\"field-label\" for=\"signalBox\">配对码</label>\n        <textarea id=\"signalBox\" class=\"signal-box\" placeholder=\"房主：点“我是房主”后复制这里发给对象。观众：粘贴房主给你的配对码后点“我是观众”。\"></textarea>\n        <div class=\"pair-grid\">\n          <button class=\"small-button\" id=\"applySignalBtn\" type=\"button\">应用对方回应码</button>\n          <button class=\"small-button\" id=\"copySignalBtn\" type=\"button\">复制配对码</button>\n        </div>\n        <div class=\"notice\">\n          GitHub Pages 可稳定托管页面；配对成功后，播放/暂停、拖动进度、片单和聊天通过你们两台设备点对点互通，不经过服务器。\n        </div>\n      </section>\n\n      <section class=\"panel share-panel\">\n        <div class=\"panel-head\">\n          <h2>异地入口</h2>\n          <span class=\"muted\">发给对象</span>\n        </div>\n        <div class=\"share-box\">\n          <label for=\"shareUrl\">房间链接</label>\n          <input id=\"shareUrl\" type=\"text\" readonly>\n          <button class=\"primary-button\" id=\"copyUrlBtn\" type=\"button\">复制链接</button>\n        </div>\n        <div class=\"notice\">\n          打开同一个房间链接后，播放/暂停、拖动进度、片单和聊天会自动互通。若网络波动，页面会自动重试同步。\n        </div>\n      </section>\n\n      <section class=\"panel queue-panel\">\n        <div class=\"panel-head\">\n          <h2>影片队列</h2>\n          <button class=\"small-button\" id=\"clearQueueBtn\" title=\"清空新增队列\">清空</button>\n        </div>\n        <form class=\"inline-form\" id=\"queueForm\">\n          <input id=\"queueTitle\" type=\"text\" placeholder=\"片名或视频链接\" autocomplete=\"off\">\n          <button type=\"submit\" class=\"primary-button\">加入</button>\n        </form>\n        <ul class=\"queue-list\" id=\"queueList\"></ul>\n      </section>\n\n      <section class=\"panel chat-panel\">\n        <div class=\"panel-head\">\n          <h2>同频聊天</h2>\n          <span class=\"muted\">在线互通</span>\n        </div>\n        <div class=\"chat-log\" id=\"chatLog\"></div>\n        <form class=\"inline-form\" id=\"chatForm\">\n          <input id=\"chatInput\" type=\"text\" placeholder=\"发一句观影弹幕\" autocomplete=\"off\">\n          <button type=\"submit\" class=\"primary-button\">发送</button>\n        </form>\n      </section>\n\n      <section class=\"panel timeline-panel\">\n        <div class=\"panel-head\">\n          <h2>房间时间线</h2>\n          <span class=\"muted\" id=\"saveState\">已保存</span>\n        </div>\n        <ol class=\"timeline\" id=\"timelineList\"></ol>\n      </section>\n    </section>\n  </main>\n\n  <script src=\"./app.js\"></script>\n</body>\n</html>\n"},"/styles.css":{"type":"text/css; charset=utf-8","body":":root {\n  color-scheme: dark;\n  --bg: #151412;\n  --surface: #201f1b;\n  --surface-2: #282620;\n  --line: #3e3930;\n  --text: #f4efe5;\n  --muted: #b6aa98;\n  --accent: #e24c3b;\n  --accent-2: #32b6a5;\n  --warn: #d5a43a;\n  --shadow: rgba(0, 0, 0, 0.32);\n  font-family: \"Microsoft YaHei\", \"PingFang SC\", Arial, sans-serif;\n}\n\n* {\n  box-sizing: border-box;\n}\n\nhtml,\nbody {\n  min-height: 100%;\n}\n\nbody {\n  margin: 0;\n  background: var(--bg);\n  color: var(--text);\n}\n\nbutton,\ninput {\n  font: inherit;\n}\n\nbutton {\n  cursor: pointer;\n}\n\n.app-shell {\n  width: min(1440px, 100%);\n  margin: 0 auto;\n  padding: 24px;\n}\n\n.topbar {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 16px;\n  min-height: 68px;\n  margin-bottom: 18px;\n}\n\n.eyebrow {\n  margin: 0 0 6px;\n  color: var(--accent-2);\n  font-size: 13px;\n  letter-spacing: 0;\n}\n\nh1,\nh2 {\n  margin: 0;\n  letter-spacing: 0;\n}\n\nh1 {\n  font-size: 30px;\n  line-height: 1.1;\n}\n\nh2 {\n  font-size: 17px;\n  line-height: 1.25;\n}\n\n.room-chip,\n.status,\n.small-button,\n.control-button,\n.primary-button,\n.icon-button {\n  border: 1px solid var(--line);\n  border-radius: 8px;\n}\n\n.room-chip {\n  display: flex;\n  align-items: baseline;\n  gap: 10px;\n  padding: 10px 12px;\n  background: var(--surface);\n  box-shadow: 0 8px 24px var(--shadow);\n}\n\n.room-chip span,\n.muted,\n.stat-grid span {\n  color: var(--muted);\n}\n\n.room-chip strong {\n  font-size: 18px;\n}\n\n.layout {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) 360px;\n  gap: 18px;\n  align-items: start;\n}\n\n.watch-stage,\n.panel {\n  background: var(--surface);\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  box-shadow: 0 10px 30px var(--shadow);\n}\n\n.watch-stage {\n  padding: 16px;\n}\n\n.screen {\n  position: relative;\n  overflow: hidden;\n  border-radius: 8px;\n  background: #0c0b0a;\n  aspect-ratio: 16 / 9;\n  border: 1px solid #090807;\n}\n\n.poster {\n  width: 100%;\n  height: 100%;\n  display: block;\n  object-fit: cover;\n}\n\n.screen-overlay {\n  position: absolute;\n  inset: auto 0 0;\n  display: flex;\n  align-items: end;\n  justify-content: space-between;\n  gap: 12px;\n  padding: 18px;\n  background: rgba(0, 0, 0, 0.62);\n}\n\n.screen-overlay h2 {\n  font-size: 26px;\n}\n\n.icon-button {\n  width: 42px;\n  height: 42px;\n  background: rgba(255, 255, 255, 0.08);\n  color: var(--text);\n  font-size: 24px;\n}\n\n.progress-block {\n  margin-top: 14px;\n}\n\n.time-row {\n  display: flex;\n  justify-content: space-between;\n  margin-bottom: 8px;\n  color: var(--muted);\n  font-variant-numeric: tabular-nums;\n}\n\n.range {\n  width: 100%;\n  accent-color: var(--accent);\n}\n\n.controls {\n  display: grid;\n  grid-template-columns: repeat(4, minmax(0, 1fr));\n  gap: 10px;\n  margin-top: 14px;\n}\n\n.control-button,\n.primary-button,\n.small-button {\n  min-height: 40px;\n  padding: 0 12px;\n  color: var(--text);\n}\n\n.control-button,\n.small-button {\n  background: var(--surface-2);\n}\n\n.primary-button {\n  background: var(--accent);\n  border-color: #ff6a55;\n  font-weight: 700;\n}\n\n.side-panel,\n.workspace {\n  display: grid;\n  gap: 18px;\n}\n\n.panel {\n  padding: 16px;\n}\n\n.panel-head {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 10px;\n  margin-bottom: 14px;\n}\n\n.status {\n  padding: 5px 9px;\n  font-size: 13px;\n  font-weight: 700;\n}\n\n.status.good {\n  color: #061f1b;\n  background: var(--accent-2);\n  border-color: var(--accent-2);\n}\n\n.status.warn {\n  color: #231800;\n  background: var(--warn);\n  border-color: var(--warn);\n}\n\n.stat-grid {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 10px;\n}\n\n.stat-grid div {\n  min-height: 72px;\n  padding: 12px;\n  background: var(--surface-2);\n  border: 1px solid var(--line);\n  border-radius: 8px;\n}\n\n.stat-grid strong {\n  display: block;\n  margin-top: 8px;\n  font-size: 20px;\n  font-variant-numeric: tabular-nums;\n}\n\n.member-list,\n.queue-list,\n.timeline {\n  margin: 0;\n  padding: 0;\n  list-style: none;\n}\n\n.member-list li,\n.queue-list li,\n.timeline li {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 12px;\n  padding: 10px 0;\n  border-top: 1px solid var(--line);\n}\n\n.member-name {\n  display: flex;\n  align-items: center;\n  gap: 9px;\n}\n\n.avatar {\n  width: 28px;\n  height: 28px;\n  display: inline-grid;\n  place-items: center;\n  border-radius: 50%;\n  color: #14110e;\n  background: var(--accent-2);\n  font-weight: 700;\n}\n\n.drift {\n  color: var(--muted);\n  font-variant-numeric: tabular-nums;\n}\n\n.workspace {\n  grid-template-columns: minmax(260px, 1fr) minmax(240px, 0.9fr) minmax(260px, 1fr) minmax(320px, 1.15fr) minmax(260px, 1fr);\n  margin-top: 18px;\n}\n\n.inline-form {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) auto;\n  gap: 10px;\n  margin-bottom: 12px;\n}\n\ninput[type=\"text\"] {\n  width: 100%;\n  min-height: 42px;\n  padding: 0 12px;\n  color: var(--text);\n  background: #171512;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  outline: none;\n}\n\ninput[type=\"text\"]:focus {\n  border-color: var(--accent-2);\n}\n\ninput[readonly] {\n  color: var(--muted);\n}\n\n.compact-form {\n  grid-template-columns: minmax(0, 1fr) 76px;\n}\n\n.share-box {\n  display: grid;\n  gap: 10px;\n}\n\n.share-box label {\n  color: var(--muted);\n  font-size: 13px;\n}\n\n.notice {\n  margin-top: 14px;\n  padding: 12px;\n  color: var(--muted);\n  background: var(--surface-2);\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  line-height: 1.6;\n}\n\n.pair-grid {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 10px;\n  margin-bottom: 12px;\n}\n\n.field-label {\n  display: block;\n  margin-bottom: 8px;\n  color: var(--muted);\n  font-size: 13px;\n}\n\n.signal-box {\n  width: 100%;\n  min-height: 118px;\n  resize: vertical;\n  padding: 10px 12px;\n  color: var(--text);\n  background: #171512;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  outline: none;\n  font: 13px/1.5 Consolas, \"Microsoft YaHei\", monospace;\n  overflow-wrap: anywhere;\n}\n\n.signal-box:focus {\n  border-color: var(--accent-2);\n}\n\n.queue-meta,\n.timeline time,\n.chat-meta {\n  color: var(--muted);\n  font-size: 13px;\n  font-variant-numeric: tabular-nums;\n}\n\n.chat-log {\n  height: 250px;\n  overflow: auto;\n  padding-right: 6px;\n}\n\n.chat-message {\n  padding: 9px 0;\n  border-top: 1px solid var(--line);\n}\n\n.chat-message strong {\n  display: inline-block;\n  margin-right: 8px;\n}\n\n.timeline {\n  counter-reset: step;\n}\n\n.timeline li {\n  align-items: start;\n  justify-content: start;\n}\n\n.timeline li::before {\n  counter-increment: step;\n  content: counter(step);\n  width: 24px;\n  height: 24px;\n  display: inline-grid;\n  place-items: center;\n  flex: 0 0 auto;\n  border-radius: 50%;\n  color: #120f0c;\n  background: var(--warn);\n  font-weight: 700;\n}\n\n@media (max-width: 1040px) {\n  .layout,\n  .workspace {\n    grid-template-columns: 1fr;\n  }\n}\n\n@media (max-width: 640px) {\n  .app-shell {\n    padding: 14px;\n  }\n\n  .topbar,\n  .screen-overlay,\n  .panel-head {\n    align-items: stretch;\n    flex-direction: column;\n  }\n\n  .controls {\n    grid-template-columns: 1fr 1fr;\n  }\n\n  .stat-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .inline-form {\n    grid-template-columns: 1fr;\n  }\n}\n"},"/app.js":{"type":"application/javascript; charset=utf-8","body":"const prefsKey = \"tongpin-cinema-prefs-v2\";\n\nconst defaultRoom = {\n  roomCode: \"TP-0726\",\n  playing: false,\n  current: 768,\n  duration: 6480,\n  updatedAt: Date.now(),\n  favorite: false,\n  title: \"今晚的片单\",\n  queue: [\n    { title: \"片头前 3 分钟集合\", meta: \"20:30\" },\n    { title: \"正片同步播放\", meta: \"20:35\" },\n    { title: \"片后 10 分钟语音复盘\", meta: \"22:25\" }\n  ],\n  members: [],\n  chat: [\n    { who: \"房主\", text: \"进入同一个链接后，播放状态会自动互通。\", time: \"20:28\" }\n  ],\n  timeline: [\n    { time: \"20:20\", text: \"创建房间并确认片源\" },\n    { time: \"20:35\", text: \"房主点击同步播放\" }\n  ]\n};\n\nlet prefs = loadPrefs();\nlet state = { ...structuredClone(defaultRoom), roomCode: prefs.roomCode };\nlet ticker = null;\nlet polling = null;\nlet lastVersion = 0;\nlet dragging = false;\nlet peerConnection = null;\nlet peerChannel = null;\n\nconst $ = (id) => document.getElementById(id);\n\nfunction loadPrefs() {\n  const params = new URLSearchParams(window.location.search);\n  const room = params.get(\"room\");\n  try {\n    const stored = JSON.parse(localStorage.getItem(prefsKey)) || {};\n    return {\n      roomCode: room || stored.roomCode || defaultRoom.roomCode,\n      viewerName: stored.viewerName || \"我\",\n      clientId: stored.clientId || crypto.randomUUID()\n    };\n  } catch {\n    return {\n      roomCode: room || defaultRoom.roomCode,\n      viewerName: \"我\",\n      clientId: crypto.randomUUID()\n    };\n  }\n}\n\nfunction savePrefs() {\n  localStorage.setItem(prefsKey, JSON.stringify(prefs));\n}\n\nfunction formatTime(value) {\n  const safe = Math.max(0, Math.floor(value));\n  const hours = Math.floor(safe / 3600);\n  const mins = Math.floor((safe % 3600) / 60);\n  const secs = safe % 60;\n  return [hours, mins, secs].map((part) => String(part).padStart(2, \"0\")).join(\":\");\n}\n\nfunction currentPlaybackTime(room = state) {\n  if (!room.playing) return room.current;\n  const elapsed = (Date.now() - room.updatedAt) / 1000;\n  return Math.min(room.duration, room.current + elapsed);\n}\n\nfunction shareUrl() {\n  const url = new URL(window.location.href);\n  url.searchParams.set(\"room\", state.roomCode);\n  return url.toString();\n}\n\nfunction nowHHMM() {\n  const now = new Date();\n  return `${String(now.getHours()).padStart(2, \"0\")}:${String(now.getMinutes()).padStart(2, \"0\")}`;\n}\n\nfunction mergeRoom(next) {\n  if (!next || typeof next !== \"object\") return;\n  state = { ...state, ...next };\n  lastVersion = next.version || lastVersion;\n  prefs.roomCode = state.roomCode;\n  savePrefs();\n  render();\n}\n\nasync function apiGetRoom() {\n  const url = `/api/room?room=${encodeURIComponent(prefs.roomCode)}&clientId=${encodeURIComponent(prefs.clientId)}&name=${encodeURIComponent(prefs.viewerName)}`;\n  const response = await fetch(url, { cache: \"no-store\" });\n  if (!response.ok) throw new Error(`room ${response.status}`);\n  return response.json();\n}\n\nasync function apiEvent(type, payload = {}) {\n  const response = await fetch(\"/api/event\", {\n    method: \"POST\",\n    headers: { \"content-type\": \"application/json\" },\n    body: JSON.stringify({\n      room: prefs.roomCode,\n      clientId: prefs.clientId,\n      name: prefs.viewerName,\n      type,\n      payload\n    })\n  });\n  if (!response.ok) throw new Error(`event ${response.status}`);\n  return response.json();\n}\n\nasync function pollRoom() {\n  try {\n    const room = await apiGetRoom();\n    $(\"saveState\").textContent = \"在线同步\";\n    mergeRoom(room);\n  } catch {\n    $(\"saveState\").textContent = \"离线重试\";\n  }\n}\n\nasync function sendEvent(type, payload = {}) {\n  applyRoomEvent(type, payload, prefs.viewerName);\n  sendPeerEvent(type, payload);\n  try {\n    const room = await apiEvent(type, payload);\n    $(\"saveState\").textContent = isPeerConnected() ? \"点对点同步\" : \"已同步\";\n    mergeRoom(room);\n  } catch {\n    $(\"saveState\").textContent = isPeerConnected() ? \"点对点同步\" : \"离线/未同步\";\n  }\n}\n\nfunction applyRoomEvent(type, payload, actor = \"成员\") {\n  if (type === \"playback\") {\n    state.playing = payload.playing;\n    state.current = payload.current;\n    state.updatedAt = Date.now();\n    state.timeline.unshift({ time: nowHHMM(), text: actor + (payload.playing ? \" 开始播放\" : \" 暂停播放\") });\n  }\n  if (type === \"seek\") {\n    state.current = payload.current;\n    state.updatedAt = Date.now();\n    state.timeline.unshift({ time: nowHHMM(), text: actor + \" 拖动到 \" + formatTime(payload.current) });\n  }\n  if (type === \"sync\") {\n    state.current = payload.current;\n    state.updatedAt = Date.now();\n    state.timeline.unshift({ time: nowHHMM(), text: actor + \" 发起同步\" });\n  }\n  if (type === \"queue:add\") {\n    state.queue.push({ title: payload.title, meta: \"待播放\" });\n    state.title = payload.title;\n    state.timeline.unshift({ time: nowHHMM(), text: actor + \" 加入片单：\" + payload.title });\n  }\n  if (type === \"queue:clear\") {\n    state.queue = defaultRoom.queue;\n    state.timeline.unshift({ time: nowHHMM(), text: actor + \" 恢复默认片单\" });\n  }\n  if (type === \"chat\") {\n    state.chat.push({ who: actor, text: payload.text, time: nowHHMM() });\n    state.chat = state.chat.slice(-40);\n  }\n  if (type === \"favorite\") {\n    state.favorite = Boolean(payload.favorite);\n  }\n  if (type === \"identity\") {\n    upsertMember({ clientId: payload.clientId || \"peer\", name: actor, drift: \"+0.00s\" });\n  }\n  state.timeline = state.timeline.slice(0, 10);\n  render();\n}\n\nfunction upsertMember(member) {\n  const id = member.clientId || member.name;\n  const existing = state.members.find((item) => (item.clientId || item.name) === id);\n  if (existing) {\n    Object.assign(existing, member);\n  } else {\n    state.members.push(member);\n  }\n}\n\nfunction render() {\n  const current = currentPlaybackTime();\n  $(\"roomCode\").textContent = state.roomCode;\n  $(\"viewerName\").value = prefs.viewerName;\n  $(\"shareUrl\").value = shareUrl();\n  $(\"movieTitle\").textContent = state.title;\n  $(\"currentTime\").textContent = formatTime(current);\n  $(\"hostTime\").textContent = formatTime(current);\n  $(\"duration\").textContent = formatTime(state.duration);\n  if (!dragging) {\n    $(\"progressRange\").value = Math.floor(current);\n  }\n  $(\"progressRange\").max = state.duration;\n  $(\"playBtn\").textContent = state.playing ? \"Ⅱ 暂停\" : \"▶ 播放\";\n  $(\"favoriteBtn\").textContent = state.favorite ? \"★\" : \"☆\";\n  $(\"memberCount\").textContent = String(state.members.length);\n\n  const self = state.members.find((member) => member.clientId === prefs.clientId);\n  const drift = self?.drift || \"+0.00s\";\n  $(\"latency\").textContent = drift;\n  const driftValue = Math.max(...state.members.map((member) => Math.abs(parseFloat(member.drift) || 0)), 0);\n  $(\"syncBadge\").className = driftValue > 1 ? \"status warn\" : \"status good\";\n  $(\"syncBadge\").textContent = driftValue > 1 ? \"需同步\" : \"同频\";\n\n  renderMembers();\n  renderQueue();\n  renderChat();\n  renderTimeline();\n}\n\nfunction renderMembers() {\n  $(\"memberList\").innerHTML = state.members.map((member) => `\n    <li>\n      <span class=\"member-name\">\n        <span class=\"avatar\">${member.name.slice(0, 1)}</span>\n        <span>${member.name}${member.host ? \" · 房主\" : \"\"}${member.clientId === prefs.clientId ? \" · 我\" : \"\"}</span>\n      </span>\n      <span class=\"drift\">${member.drift}</span>\n    </li>\n  `).join(\"\");\n}\n\nfunction isPeerConnected() {\n  return peerChannel && peerChannel.readyState === \"open\";\n}\n\nfunction setPeerStatus(text) {\n  $(\"p2pStatus\").textContent = text;\n  if (isPeerConnected()) {\n    $(\"saveState\").textContent = \"点对点同步\";\n  }\n}\n\nfunction encodeSignal(value) {\n  return btoa(JSON.stringify(value));\n}\n\nfunction decodeSignal(value) {\n  return JSON.parse(atob(value.trim()));\n}\n\nfunction waitForIceComplete(pc) {\n  if (pc.iceGatheringState === \"complete\") return Promise.resolve();\n  return new Promise((resolve) => {\n    const timeout = setTimeout(resolve, 2500);\n    pc.addEventListener(\"icegatheringstatechange\", () => {\n      if (pc.iceGatheringState === \"complete\") {\n        clearTimeout(timeout);\n        resolve();\n      }\n    });\n  });\n}\n\nfunction createPeerConnection() {\n  const pc = new RTCPeerConnection({\n    iceServers: [{ urls: \"stun:stun.l.google.com:19302\" }]\n  });\n  pc.addEventListener(\"connectionstatechange\", () => {\n    setPeerStatus(pc.connectionState === \"connected\" ? \"已直连\" : pc.connectionState);\n  });\n  return pc;\n}\n\nfunction bindChannel(channel) {\n  peerChannel = channel;\n  channel.addEventListener(\"open\", () => {\n    setPeerStatus(\"已直连\");\n    upsertMember({ clientId: prefs.clientId, name: prefs.viewerName, drift: \"+0.00s\" });\n    sendPeerEvent(\"identity\", { clientId: prefs.clientId });\n    sendPeerEvent(\"state:snapshot\", { state });\n    render();\n  });\n  channel.addEventListener(\"close\", () => setPeerStatus(\"已断开\"));\n  channel.addEventListener(\"message\", (event) => {\n    const message = JSON.parse(event.data);\n    if (message.from === prefs.clientId) return;\n    if (message.type === \"state:snapshot\" && message.payload?.state) {\n      mergePeerState(message.payload.state, message.name);\n      return;\n    }\n    applyRoomEvent(message.type, message.payload || {}, message.name || \"对象\");\n  });\n}\n\nfunction mergePeerState(peerState, actor) {\n  state = {\n    ...state,\n    ...peerState,\n    roomCode: prefs.roomCode,\n    members: [...state.members, ...peerState.members]\n  };\n  const seen = new Map();\n  state.members.forEach((member) => seen.set(member.clientId || member.name, member));\n  state.members = [...seen.values()];\n  upsertMember({ clientId: \"peer\", name: actor || \"对象\", drift: \"+0.00s\" });\n  render();\n}\n\nfunction sendPeerEvent(type, payload = {}) {\n  if (!isPeerConnected()) return;\n  peerChannel.send(JSON.stringify({\n    type,\n    payload,\n    from: prefs.clientId,\n    name: prefs.viewerName,\n    sentAt: Date.now()\n  }));\n}\n\nfunction renderQueue() {\n  $(\"queueList\").innerHTML = state.queue.map((item, index) => `\n    <li>\n      <span>${item.title}</span>\n      <span class=\"queue-meta\">${item.meta || `#${index + 1}`}</span>\n    </li>\n  `).join(\"\");\n}\n\nfunction renderChat() {\n  $(\"chatLog\").innerHTML = state.chat.map((message) => `\n    <div class=\"chat-message\">\n      <div class=\"chat-meta\">${message.time}</div>\n      <strong>${message.who}</strong><span>${message.text}</span>\n    </div>\n  `).join(\"\");\n  $(\"chatLog\").scrollTop = $(\"chatLog\").scrollHeight;\n}\n\nfunction renderTimeline() {\n  $(\"timelineList\").innerHTML = state.timeline.map((item) => `\n    <li>\n      <div>\n        <time>${item.time}</time>\n        <div>${item.text}</div>\n      </div>\n    </li>\n  `).join(\"\");\n}\n\n$(\"playBtn\").addEventListener(\"click\", () => {\n  sendEvent(\"playback\", {\n    playing: !state.playing,\n    current: currentPlaybackTime()\n  });\n});\n\n$(\"backBtn\").addEventListener(\"click\", () => {\n  sendEvent(\"seek\", { current: Math.max(0, currentPlaybackTime() - 15) });\n});\n\n$(\"forwardBtn\").addEventListener(\"click\", () => {\n  sendEvent(\"seek\", { current: Math.min(state.duration, currentPlaybackTime() + 15) });\n});\n\n$(\"syncBtn\").addEventListener(\"click\", () => {\n  sendEvent(\"sync\", { current: currentPlaybackTime() });\n});\n\n$(\"favoriteBtn\").addEventListener(\"click\", () => {\n  sendEvent(\"favorite\", { favorite: !state.favorite });\n});\n\n$(\"progressRange\").addEventListener(\"input\", (event) => {\n  dragging = true;\n  const current = Number(event.target.value);\n  $(\"currentTime\").textContent = formatTime(current);\n  $(\"hostTime\").textContent = formatTime(current);\n});\n\n$(\"progressRange\").addEventListener(\"change\", (event) => {\n  dragging = false;\n  sendEvent(\"seek\", { current: Number(event.target.value) });\n});\n\n$(\"queueForm\").addEventListener(\"submit\", (event) => {\n  event.preventDefault();\n  const title = $(\"queueTitle\").value.trim();\n  if (!title) return;\n  $(\"queueTitle\").value = \"\";\n  sendEvent(\"queue:add\", { title });\n});\n\n$(\"chatForm\").addEventListener(\"submit\", (event) => {\n  event.preventDefault();\n  const text = $(\"chatInput\").value.trim();\n  if (!text) return;\n  $(\"chatInput\").value = \"\";\n  sendEvent(\"chat\", { text });\n});\n\n$(\"identityForm\").addEventListener(\"submit\", (event) => {\n  event.preventDefault();\n  const name = $(\"viewerName\").value.trim();\n  if (!name) return;\n  prefs.viewerName = name.slice(0, 12);\n  savePrefs();\n  sendEvent(\"identity\", {});\n});\n\n$(\"clearQueueBtn\").addEventListener(\"click\", () => {\n  sendEvent(\"queue:clear\");\n});\n\n$(\"copyInviteBtn\").addEventListener(\"click\", async () => {\n  const invite = `加入同频影院：房间 ${$(\"roomCode\").textContent}，当前时间 ${formatTime(currentPlaybackTime())}\\n${shareUrl()}`;\n  try {\n    await navigator.clipboard.writeText(invite);\n    $(\"copyInviteBtn\").textContent = \"已复制\";\n  } catch {\n    $(\"copyInviteBtn\").textContent = \"复制失败\";\n  }\n  setTimeout(() => {\n    $(\"copyInviteBtn\").textContent = \"复制邀请\";\n  }, 1400);\n});\n\n$(\"copyUrlBtn\").addEventListener(\"click\", async () => {\n  try {\n    await navigator.clipboard.writeText(shareUrl());\n    $(\"copyUrlBtn\").textContent = \"已复制\";\n  } catch {\n    $(\"copyUrlBtn\").textContent = \"复制失败\";\n  }\n  setTimeout(() => {\n    $(\"copyUrlBtn\").textContent = \"复制链接\";\n  }, 1400);\n});\n\n$(\"createOfferBtn\").addEventListener(\"click\", async () => {\n  try {\n    peerConnection = createPeerConnection();\n    bindChannel(peerConnection.createDataChannel(\"tongpin-sync\"));\n    const offer = await peerConnection.createOffer();\n    await peerConnection.setLocalDescription(offer);\n    await waitForIceComplete(peerConnection);\n    $(\"signalBox\").value = encodeSignal(peerConnection.localDescription);\n    setPeerStatus(\"等待回应码\");\n  } catch (error) {\n    $(\"signalBox\").value = \"创建失败：\" + error.message;\n    setPeerStatus(\"创建失败\");\n  }\n});\n\n$(\"createAnswerBtn\").addEventListener(\"click\", async () => {\n  try {\n    const offer = decodeSignal($(\"signalBox\").value);\n    peerConnection = createPeerConnection();\n    peerConnection.addEventListener(\"datachannel\", (event) => bindChannel(event.channel));\n    await peerConnection.setRemoteDescription(offer);\n    const answer = await peerConnection.createAnswer();\n    await peerConnection.setLocalDescription(answer);\n    await waitForIceComplete(peerConnection);\n    $(\"signalBox\").value = encodeSignal(peerConnection.localDescription);\n    setPeerStatus(\"回应码已生成\");\n  } catch (error) {\n    $(\"signalBox\").value = \"回应失败：\" + error.message;\n    setPeerStatus(\"回应失败\");\n  }\n});\n\n$(\"applySignalBtn\").addEventListener(\"click\", async () => {\n  try {\n    if (!peerConnection) throw new Error(\"请先点“我是房主”生成配对码\");\n    const answer = decodeSignal($(\"signalBox\").value);\n    await peerConnection.setRemoteDescription(answer);\n    setPeerStatus(\"正在连接\");\n  } catch (error) {\n    $(\"signalBox\").value = \"应用失败：\" + error.message;\n    setPeerStatus(\"应用失败\");\n  }\n});\n\n$(\"copySignalBtn\").addEventListener(\"click\", async () => {\n  try {\n    await navigator.clipboard.writeText($(\"signalBox\").value);\n    $(\"copySignalBtn\").textContent = \"已复制\";\n  } catch {\n    $(\"copySignalBtn\").textContent = \"复制失败\";\n  }\n  setTimeout(() => {\n    $(\"copySignalBtn\").textContent = \"复制配对码\";\n  }, 1400);\n});\n\nfunction startTicker() {\n  ticker = setInterval(render, 1000);\n  polling = setInterval(pollRoom, 1200);\n}\n\nrender();\npollRoom();\nstartTicker();\n"},"/assets/theater-poster.svg":{"type":"image/svg+xml; charset=utf-8","body":"<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"1600\" height=\"900\" viewBox=\"0 0 1600 900\" role=\"img\" aria-label=\"同频影院海报\">\n  <defs>\n    <linearGradient id=\"beam\" x1=\"0\" x2=\"1\" y1=\"0\" y2=\"1\">\n      <stop offset=\"0\" stop-color=\"#f4efe5\" stop-opacity=\"0.38\"/>\n      <stop offset=\"1\" stop-color=\"#f4efe5\" stop-opacity=\"0\"/>\n    </linearGradient>\n  </defs>\n  <rect width=\"1600\" height=\"900\" fill=\"#11100d\"/>\n  <rect x=\"80\" y=\"68\" width=\"1440\" height=\"710\" rx=\"20\" fill=\"#211f1a\" stroke=\"#4b4337\" stroke-width=\"6\"/>\n  <rect x=\"132\" y=\"118\" width=\"1336\" height=\"610\" rx=\"12\" fill=\"#080807\"/>\n  <path d=\"M210 180h1180v500H210z\" fill=\"#181512\"/>\n  <path d=\"M210 180l1180 500H210z\" fill=\"url(#beam)\"/>\n  <path d=\"M1390 180L210 680h1180z\" fill=\"#32b6a5\" opacity=\"0.08\"/>\n  <g fill=\"#e24c3b\">\n    <circle cx=\"372\" cy=\"742\" r=\"18\"/>\n    <circle cx=\"430\" cy=\"742\" r=\"18\"/>\n    <circle cx=\"488\" cy=\"742\" r=\"18\"/>\n    <circle cx=\"546\" cy=\"742\" r=\"18\"/>\n    <circle cx=\"604\" cy=\"742\" r=\"18\"/>\n  </g>\n  <g fill=\"#d5a43a\">\n    <rect x=\"312\" y=\"314\" width=\"96\" height=\"190\" rx=\"12\"/>\n    <rect x=\"440\" y=\"250\" width=\"110\" height=\"254\" rx=\"12\"/>\n    <rect x=\"582\" y=\"354\" width=\"96\" height=\"150\" rx=\"12\"/>\n  </g>\n  <g fill=\"#32b6a5\">\n    <rect x=\"922\" y=\"274\" width=\"280\" height=\"42\" rx=\"8\"/>\n    <rect x=\"922\" y=\"350\" width=\"360\" height=\"42\" rx=\"8\"/>\n    <rect x=\"922\" y=\"426\" width=\"230\" height=\"42\" rx=\"8\"/>\n  </g>\n  <text x=\"798\" y=\"806\" fill=\"#f4efe5\" font-family=\"Microsoft YaHei, Arial, sans-serif\" font-size=\"54\" text-anchor=\"middle\" letter-spacing=\"0\">同频影院</text>\n  <text x=\"798\" y=\"852\" fill=\"#b6aa98\" font-family=\"Microsoft YaHei, Arial, sans-serif\" font-size=\"26\" text-anchor=\"middle\" letter-spacing=\"0\">一起开场，一起暂停，一起看完</text>\n</svg>\n"}};
const rooms = globalThis.__tongpinRooms || new Map();
globalThis.__tongpinRooms = rooms;

const defaultRoom = {
  playing: false,
  current: 768,
  duration: 6480,
  updatedAt: Date.now(),
  version: 1,
  favorite: false,
  title: "今晚的片单",
  queue: [
    { title: "片头前 3 分钟集合", meta: "20:30" },
    { title: "正片同步播放", meta: "20:35" },
    { title: "片后 10 分钟语音复盘", meta: "22:25" }
  ],
  members: [],
  chat: [
    { who: "房主", text: "进入同一个链接后，播放状态会自动互通。", time: "20:28" }
  ],
  timeline: [
    { time: "20:20", text: "创建房间并确认片源" },
    { time: "20:35", text: "房主点击同步播放" }
  ]
};

function json(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      "content-type": "application/json; charset=utf-8",
      "cache-control": "no-store"
    }
  });
}

function nowHHMM() {
  const now = new Date();
  return String(now.getHours()).padStart(2, "0") + ":" + String(now.getMinutes()).padStart(2, "0");
}

function clone(value) {
  return JSON.parse(JSON.stringify(value));
}

function playbackCurrent(room) {
  if (!room.playing) return room.current;
  const elapsed = (Date.now() - room.updatedAt) / 1000;
  return Math.min(room.duration, room.current + elapsed);
}

function stateRequest(roomCode) {
  return new Request("https://tongpin.local/state/" + encodeURIComponent(roomCode || "TP-0726"));
}

async function readCachedRoom(roomCode) {
  try {
    if (typeof caches === "undefined") return null;
    const response = await caches.default.match(stateRequest(roomCode));
    if (!response) return null;
    return response.json().catch(() => null);
  } catch {
    return null;
  }
}

async function writeCachedRoom(room) {
  try {
    if (typeof caches === "undefined") return;
    await caches.default.put(
      stateRequest(room.roomCode),
      new Response(JSON.stringify(room), {
        headers: {
          "content-type": "application/json; charset=utf-8",
          "cache-control": "public, max-age=86400"
        }
      })
    );
  } catch {
    return;
  }
}

async function getRoom(roomCode) {
  const code = roomCode || "TP-0726";
  const cached = await readCachedRoom(code);
  if (cached) {
    rooms.set(code, cached);
    return cached;
  }
  if (!rooms.has(code)) {
    rooms.set(code, { ...clone(defaultRoom), roomCode: code, createdAt: Date.now() });
  }
  return rooms.get(code);
}

function touchMember(room, clientId, name) {
  const id = clientId || "guest";
  const safeName = (name || "我").slice(0, 12);
  const current = playbackCurrent(room);
  let member = room.members.find((item) => item.clientId === id);
  if (!member) {
    member = {
      clientId: id,
      name: safeName,
      host: room.members.length === 0,
      joinedAt: Date.now(),
      lastSeen: Date.now(),
      drift: "+0.00s"
    };
    room.members.push(member);
    room.timeline.unshift({ time: nowHHMM(), text: safeName + " 进入房间" });
  }
  member.name = safeName;
  member.lastSeen = Date.now();
  member.drift = (Math.random() > 0.5 ? "+" : "-") + (Math.random() * 0.35).toFixed(2) + "s";
  room.members = room.members.filter((item) => Date.now() - item.lastSeen < 1000 * 60 * 10);
  room.current = current;
  room.updatedAt = Date.now();
  return member;
}

function bump(room, text) {
  room.version += 1;
  room.timeline.unshift({ time: nowHHMM(), text });
  room.timeline = room.timeline.slice(0, 10);
  room.updatedAt = Date.now();
}

function publicRoom(room) {
  const copy = clone(room);
  copy.current = playbackCurrent(room);
  copy.updatedAt = Date.now();
  return copy;
}

async function handleApi(request, url) {
  if (url.pathname === "/api/room" && request.method === "GET") {
    const room = await getRoom(url.searchParams.get("room"));
    touchMember(room, url.searchParams.get("clientId"), url.searchParams.get("name"));
    await writeCachedRoom(room);
    return json(publicRoom(room));
  }

  if (url.pathname === "/api/event" && request.method === "POST") {
    const body = await request.json().catch(() => null);
    if (!body) return json({ error: "invalid json" }, 400);
    const room = await getRoom(body.room);
    const member = touchMember(room, body.clientId, body.name);
    const payload = body.payload || {};
    const actor = member.name || "成员";

    if (body.type === "playback") {
      room.current = Number(payload.current) || playbackCurrent(room);
      room.playing = Boolean(payload.playing);
      bump(room, actor + (room.playing ? " 开始播放" : " 暂停播放"));
    } else if (body.type === "seek") {
      room.current = Math.max(0, Math.min(room.duration, Number(payload.current) || 0));
      bump(room, actor + " 拖动到 " + Math.floor(room.current) + " 秒");
    } else if (body.type === "sync") {
      room.current = Number(payload.current) || playbackCurrent(room);
      bump(room, actor + " 发起全员同步");
    } else if (body.type === "favorite") {
      room.favorite = Boolean(payload.favorite);
      room.version += 1;
    } else if (body.type === "queue:add" && payload.title) {
      room.queue.push({ title: String(payload.title).slice(0, 80), meta: "待播放" });
      room.title = String(payload.title).slice(0, 80);
      bump(room, actor + " 加入片单：" + room.title);
    } else if (body.type === "queue:clear") {
      room.queue = clone(defaultRoom.queue);
      bump(room, actor + " 恢复默认片单");
    } else if (body.type === "chat" && payload.text) {
      room.chat.push({ who: actor, text: String(payload.text).slice(0, 200), time: nowHHMM() });
      room.chat = room.chat.slice(-60);
      room.version += 1;
    } else if (body.type === "identity") {
      bump(room, actor + " 更新了昵称");
    } else {
      room.version += 1;
    }

    await writeCachedRoom(room);
    return json(publicRoom(room));
  }

  return json({ error: "not found" }, 404);
}

export default {
  async fetch(request) {
    const url = new URL(request.url);
    if (url.pathname.startsWith("/api/")) {
      return handleApi(request, url);
    }
    const file = files[url.pathname] || files["/"];
    return new Response(file.body, {
      headers: {
        "content-type": file.type,
        "cache-control": url.pathname === "/" || url.pathname === "/index.html" ? "no-store" : "public, max-age=3600"
      }
    });
  }
};
